const fs = require('fs');
const path = require('path');
const LEADS_DIR = 'C:\\Users\\Matth\\hoo-workspace\\engine\\leads';

const today = new Date();
const todayStr = today.toISOString().split('T')[0];

let leads = [];
try {
  const files = fs.readdirSync(LEADS_DIR).filter(f => f.endsWith('.json') && f.startsWith('LEAD-'));
  leads = files.map(f => {
    try { return JSON.parse(fs.readFileSync(path.join(LEADS_DIR, f))); }
    catch { return null; }
  }).filter(Boolean);
} catch(e) { console.error(e); }

// Categorize
const responded = leads.filter(l => l.stage === 'responded');
const overdue = leads.filter(l => {
  if (l.stage !== 'contacted') return false;
  const contactedDate = new Date(l.contacted_date || l.found_date);
  const daysSince = (today - contactedDate) / (1000 * 60 * 60 * 24);
  return daysSince >= 3;
});
const hot = leads.filter(l => l.tier === 'HOT' && l.stage === 'found');
const needsCalls = leads.filter(l => l.phone && !l.email && l.stage === 'found').slice(0,5);

const total = leads.length;
const contacted = leads.filter(l => l.stage === 'contacted').length;
const closed = leads.filter(l => l.stage === 'closed_won').length;

return [{ json: { responded, overdue, hot, needsCalls, total, contacted, closed, todayStr } }];

const { responded, overdue, hot, needsCalls, total, contacted, closed, todayStr } = $json;

let lines = [];
lines.push(`🌅 HOO DAILY BRIEFING — ${todayStr}`);
lines.push(`${'─'.repeat(40)}`);
lines.push(`📊 Pipeline: ${total} leads | ${contacted} contacted | ${closed} won`);
lines.push('');

if (responded.length > 0) {
  lines.push(`🔥 REPLIES (${responded.length}) — ACT NOW:`);
  responded.forEach(l => lines.push(`   → ${l.business} (${l.city}) — ${l.phone || 'no phone'}`));
  lines.push('');
}

if (overdue.length > 0) {
  lines.push(`⏰ FOLLOW-UPS DUE (${overdue.length}):`);
  overdue.slice(0,5).forEach(l => lines.push(`   → ${l.business} — contacted ${l.contacted_date}`));
  lines.push('');
}

if (needsCalls.length > 0) {
  lines.push(`📞 CALL TODAY — phone only (${needsCalls.length}):`);
  needsCalls.forEach(l => lines.push(`   → ${l.business} | ${l.phone} | ${l.city}`));
  lines.push('');
}

if (hot.length > 0) {
  lines.push(`⚡ NEW HOT LEADS (${hot.length} untouched):`);
  hot.slice(0,3).forEach(l => lines.push(`   → ${l.business} | ${l.city} | Score:${l.score}`));
  lines.push('');
}

lines.push(`─────────────────────────────────────`);
lines.push(`herrmanonlineoutlook.com — build free, pay on approval`);

return [{ json: { briefing: lines.join('\n'), hasUrgent: responded.length > 0 || overdue.length > 0 } }];
